            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"mfa1","text":"You want to turn on two-step sign-in for your QB Engineer account. Where do you go?","options":[{"id":"a","text":"Admin > Users > edit your profile and switch MFA on"},{"id":"b","text":"Account > Security, then click 'Enable Two-Factor Authentication' in the MFA card","isCorrect":true},{"id":"c","text":"Settings > Privacy > Two-Factor tab"},{"id":"d","text":"Sign-in screen > click the 'Set up MFA' link"}],"explanation":"You set this up from Account > Security. The Two-Factor Authentication card shows your status and has the Enable button, which opens the setup window with a QR code."},{"id":"mfa2","text":"During setup, your authenticator app can't scan the QR code. What should you do?","options":[{"id":"a","text":"Ask your admin to turn on two-step sign-in for you"},{"id":"b","text":"Click 'Can't scan? Enter key manually' to show the backup key, then type it into your app","isCorrect":true},{"id":"c","text":"Use a different browser and try again"},{"id":"d","text":"Skip setup — it will work without scanning"}],"explanation":"The setup window has a 'Can't scan? Enter key manually' link that shows a short key you can copy. Type or paste that key into your app's manual-entry option."},{"id":"mfa3","text":"You typed the six-digit code from your app but it didn't work. Why might that happen?","options":[{"id":"a","text":"Your authenticator app doesn't work with QB Engineer"},{"id":"b","text":"The code changes every 30 seconds, so the one you entered may have just expired","isCorrect":true},{"id":"c","text":"Two-step sign-in only works with Google Authenticator, not other apps"},{"id":"d","text":"You need to scan the QR code again before entering a code"}],"explanation":"Codes change every 30 seconds. If you entered one just as it was expiring, it can fail. Wait for the next code to appear in your app and try again