            ContentJson = """{"appRoute":"/account/security","startButtonLabel":"Tour Account Security","steps":[{"element":".account-page__title","popover":{"title":"Account Security Page","description":"This is Account > Security — the single place you manage how you sign in. It is laid out as cards: Change Password, Kiosk PIN, and Two-Factor Authentication. Let's walk through the first two.","side":"bottom"}},{"element":".account-page__card-grid","popover":{"title":"Security Cards","description":"Each card is one self-contained task. Changing your password does not touch your PIN or your MFA devices, and vice versa — they are fully independent.","side":"top"}},{"element":".account-page__section-label","popover":{"title":"Change Password","description":"The first card changes your browser sign-in password. Enter your Current Password (to prove it's you), then a New Password of at least 8 characters, then Confirm it. If the two new entries don't match, an inline warning appears and the button stays disabled.","side":"right"}},{"element":"app-validation-button","popover":{"title":"Change Password Button","description":"When all three fields are valid, this button commits the change. If your current password was wrong, nothing changes and you can retry — your password is never replaced unless the current one checks out. The warning icon to the left explains why the button is disabled.","side":"top"}},{"element":".security__hint","popover":{"title":"Kiosk PIN","description":"The second card sets your kiosk PIN: a 4-to-8 digit numeric code, numbers only. This is the second factor at the shop-floor kiosk — you scan your badge, then enter this PIN. It is separate from your password and is never used for browser sign-in. Setting a new PIN overwrites any previous one.","side":"right"}},{"element":".security__mfa-status","popover":{"title":"Two-Factor Authentication","description":"The third card shows your MFA status. A green banner means two-factor is enabled; a gray banner means it is not. Enabling MFA, adding devices, and recovery codes are covered in the dedicated MFA training.","side":"top"}}]}"""
