        // ── Advanced Reference (Reference) ───────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "MFA & Account Security — Advanced Reference",
            Slug = "mfa-reference",
            Summary = "Extra details: other ways to get codes, device lockout and recovery, what's tracked for security, kiosk PIN vs badge scan, and the password rules.",
